<template>
  <div class="license_body">
    <div class="AccreditInfo-row" style="height: 4vh">
      <div style="color:red;width: 100%;text-indent: 20px;font-size: 20px;">
        授权到期天数：{{ licenseDays }}天
      </div>
      <div class="AccreditInfo-col">
        <span>名称</span>
        <span>地址</span>
        <span class="copy-btn" style="background: none">操作</span>
      </div>
      <div class="AccreditInfo-col" v-for="item in licenseMacArr" :key="item.macAddress">
        <span>{{ item.name }}</span>
        <span>{{ item.macAddress }}</span>
        <span class="copy-btn" @click="copyText(item)">
              复制
            </span>
      </div>
    </div>
    <!--按钮-->
    <div class="license-btn_box">
      <input
          multiple="multiple"
          type="file"
          ref="fileUpload"
          :accept="'.json, application/json'"
          style="display: none"
          @change="fileUploadChange()"
      />
      <div class="license-btn"  @click="$refs.fileUpload.click()">上传</div>
      <div class="license-btn" @click="$emit('cancel')">关 闭</div>
    </div>
  </div>
</template>
<script>
import {licenseDaysApi, licenseMacApi, licenseUploadApi} from "@/api/System/user.js"

export default {
  name: "license",
  data() {
    return {
      licenseDays: 0,
      licenseMacArr: [],
    }
  },
  created() {
    this.getLicenseDays();
  },
  methods: {
    // 授权信息
    getLicenseDays() {
      licenseDaysApi().then(res => {
        if (res.data.code != '2000') return;
        this.licenseDays = res.data.result;
        // if (res.data.result == 0) {
        //   this.$message.error({message: "授权已过期，请联系管理员续费！", showClose: true, duration: 1500});
        // }
      })
      licenseMacApi().then(res => {
        console.log("res-=-=-=-=");
        console.log(res);
        this.licenseMacArr = res.data;
      })
    },
    copyText(item) {
      console.log('item');
      // 创建临时textarea元素
      const textarea = document.createElement('textarea')
      textarea.value = item.macAddress
      document.body.appendChild(textarea)

      // 选中并复制文本
      textarea.select()
      try {
        console.log('复制成功');
        document.execCommand('copy')
        this.$message.success({
          message: '复制成功',
          showClose: true,
          duration: 1000,
        });
      } catch (err) {
        this.$message.error({
          message: '复制失败',
          showClose: true,
          duration: 1000,
        });
      } finally {
        document.body.removeChild(textarea)
      }
    },
    fileUploadChange() {
      var getFile = this.$refs.fileUpload.files;
      var file = getFile[0]
      var fileList = []
      fileList.push(file)
      //上传文件
      let fileFormData = new FormData()
      fileFormData.append('file',file)
      licenseUploadApi(fileFormData).then(res=>{
        if(res.data.code != '2000') return this.$message.error({message:res.data.message,showClose:true,duration:1000});
        this.getLicenseDays();
        this.$refs.fileUpload.value = null;
        this.$message.success({message:res.data.message,showClose:true,duration:1000});
      })
    }
    //END!
  }
}
</script>
<style scoped lang="scss">
  .license_body{
    width: 100%;
    height: 100%;
    .AccreditInfo-row {
      width: 100%;
      height: 100%!important;
      overflow: auto;
      .AccreditInfo-col {
        width: calc(100% - 30px);
        padding: 0 15px;
        display: flex;
        justify-content: space-between;
        margin-top: 10px;

        span {
          width: calc((100% - 55px) / 2);
          color: #ffffff;
          overflow: hidden;
        }
        .copy-btn {
          width: 30px;
          white-space: nowrap;
          display: inline-block;
          background: #42b983;
          color: white;
          border: none;
          padding: 5px 10px;
          border-radius: 4px;
          cursor: pointer;
        }
        .copy-btn:hover {
          background: #33a06f;
        }
      }
    }
    .license-btn_box {
      width: 100%;
      height: 6vh;
      display: flex;
      margin-top: 10px;
      justify-content: center;
      .license-btn {
        background: url("~@/assets/image/icon-cx.png") no-repeat !important;
        background-size: 100% 100% !important;
        width: 13vh;
        height: 6vh;
        line-height: 6vh;
        color: #ffffff;
        text-align: center;
        cursor: pointer;
      }
    }
  }
</style>