<template>
  <div class="editPassWord-body">
    <div class="headerdetailPage-row" style="height: 4vh">
      <div class="detailPage-col"><span>原密码</span><span><el-input type="password"
                                                                     v-model="userForm['oldPassword']"></el-input></span>
      </div>
      <div class="detailPage-col"><span>新密码</span><span><el-input type="password"
                                                                     v-model="userForm['newPassword']"></el-input></span>
      </div>
    </div>
    <!--按钮-->
    <div class="editPassWord-btn_box">
      <div class="editPassWord-btn" @click="$emit('cancel')">取 消</div>
      <div class="editPassWord-btn" @click="updatePassWord()">保 存</div>
    </div>
  </div>
</template>

<script>
import {updatePassApi} from "@/api/System/user.js"

export default {
  name: "editPassword",
  data() {
    return {
      userForm: {
        oldPassword: '',
        newPassword: ''
      }
    }
  },
  methods: {
    //修改密码
    updatePassWord() {
      console.log("修改密码");
      //if(this.isUpdate == true){
      //this.userForm.userId = JSON.parse(localStorage.getItem("userMsg")).userId
      updatePassApi(this.userForm).then(res => {
        if (res.data.code != '2000') return this.$message.error({
          message: res.data.message,
          showClose: true,
          duration: 1000
        });
        this.$message.success({message: "密码修改成功！请重新登录！", showClose: true, duration: 1500});
        this.$router.push('/login')
      })
      //}
    }
  }
}

</script>


<style scoped lang="scss">
.editPassWord-body{
  width: 100%;
  height: 100%;
  position: relative;
  .headerdetailPage-row {
    width: 100%;
    display: flex;
    justify-content: flex-start;
    font-size: 14px;
    margin-bottom: 15px;
    flex-wrap: wrap;

    .detailPage-col {
      width: 100%;
      display: flex;
      align-items: center;
      margin-top: 30px;

      .el-select, .el-input {
        width: 80% !important;
      }

      > span {
        color: #ffffff;
        margin-right: 10px;
        white-space: nowrap;
      }

      > span:nth-of-type(1) {
        width: 90px;
        display: inline-block;
        text-align: right;
        white-space: nowrap;

        i {
          font-size: 14px;
          color: red;
          margin-right: 10px;
        }
      }

      > span:nth-of-type(2) {
        width: calc(100% - 90px);
        color: #ffffff;
      }

      &.detailPage-col2 {
        width: 100%;

        > span:nth-of-type(2) {
          width: calc(100% - 90px);
          color: #ffffff;
        }
      }

      &.detailPage-col3 {
        width: 100%;

        > span:nth-of-type(2) {
          width: calc(33% - 90px);
          color: #ffffff;
        }
      }
    }

    ::v-deep .el-input__inner {
      height: 40px;
      background: transparent !important;
      border: 1px solid #9BB1C2;
      color: #fff !important;
    }

  }

  .editPassWord-btn_box {
    width: 100%;
    height: 6vh;
    display: flex;
    justify-content: center;
    position: absolute;
    bottom: -5vh;
    left:0;
    .editPassWord-btn {
      background: url("~@/assets/image/icon-cx.png") no-repeat !important;
      background-size: 100% 100% !important;
      width: 13vh;
      height: 6vh;
      line-height: 6vh;
      color: #ffffff;
      text-align: center;
      cursor: pointer;
    }
  }
}

</style>