import request from '@/utils/request'


//注册用户
export function registerUserApi(query) {
    return request({
      url: '/apiIP/sys-user/add',
      method: 'post',
      data: query,
    })
}
//查询用户
export function queryUserApi(query) {
    return request({
        url: '/apiIP/sys-user/query',
        method: 'post',
        data: query,
    })
}
//删除用户
export function deleteUserApi(query) {
    return request({
        url: '/apiIP/sys-user/delByIds',
        method: 'post',
        data: query,

    })
}
//批量删除用户
export function deleteAllUserApi(query) {
    return request({
        url: '/apiIP/system/user/delete/batch',
        method: 'get',
        params: query,
    })
}
